SELECT * , (SELECT lyr_nm FROM xeus.gis_lyr_list WHERE tbl_id = f_table_name) , (SELECT (table_type = 'VIEW') as is_view FROM information_schema.tables WHERE table_schema = f_table_schema AND table_name = f_table_name)
FROM geometry_columns
WHERE f_table_schema IN ('public', 'xeus', 'draw', 'excel', 'shp')
${sortCol} ${sortTyp}
f_table_schema, f_table_name asc
LIMIT ${limit} OFFSET ${offset}
